// Currency Input Component - allows natural number pad entry
const CurrencyInput = ({ value, onChange, className = '', placeholder = '0.00', disabled = false }) => {
  const [displayValue, setDisplayValue] = useState('');
  const inputRef = useRef(null);
  
  // Format number for display
  const formatForDisplay = (num) => {
    if (num === 0 || num === null || num === undefined) return '';
    return '$' + num.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  };
  
  // Parse input string to number
  const parseValue = (str) => {
    if (!str) return 0;
    // Remove everything except digits, decimal point, and minus sign
    const cleaned = str.replace(/[^0-9.-]/g, '');
    return parseFloat(cleaned) || 0;
  };
  
  // Initialize display value from prop
  useEffect(() => {
    if (document.activeElement !== inputRef.current) {
      setDisplayValue(formatForDisplay(value));
    }
  }, [value]);
  
  const handleFocus = () => {
    // On focus, show raw number without formatting for easier editing
    if (value) {
      setDisplayValue(value.toString());
    }
  };
  
  const handleChange = (e) => {
    // Allow typing naturally - only allow valid currency characters
    const input = e.target.value;
    // Allow digits, commas, decimal point, minus sign, and dollar sign
    if (/^\$?-?[\d,]*\.?\d*$/.test(input) || input === '') {
      setDisplayValue(input);
    }
  };
  
  const handleBlur = () => {
    const numValue = parseValue(displayValue);
    onChange(numValue);
    setDisplayValue(formatForDisplay(numValue));
  };
  
  const handleKeyDown = (e) => {
    // Submit on Enter
    if (e.key === 'Enter') {
      e.target.blur();
    }
  };
  
  return (
    <input
      ref={inputRef}
      type="text"
      inputMode="decimal"
      value={displayValue}
      onChange={handleChange}
      onFocus={handleFocus}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      placeholder={placeholder}
      disabled={disabled}
      className={className}
    />
  );
};

// Number Input Component - for quantities, percentages, etc.
const NumberInput = ({ value, onChange, className = '', placeholder = '0', decimals = 0, disabled = false }) => {
  const [displayValue, setDisplayValue] = useState('');
  const inputRef = useRef(null);
  
  const formatForDisplay = (num) => {
    if (num === 0 || num === null || num === undefined) return '';
    return num.toLocaleString('en-US', { minimumFractionDigits: decimals, maximumFractionDigits: decimals });
  };
  
  const parseValue = (str) => {
    if (!str) return 0;
    const cleaned = str.replace(/[^0-9.-]/g, '');
    return decimals > 0 ? parseFloat(cleaned) || 0 : parseInt(cleaned) || 0;
  };
  
  useEffect(() => {
    if (document.activeElement !== inputRef.current) {
      setDisplayValue(formatForDisplay(value));
    }
  }, [value]);
  
  const handleFocus = () => {
    if (value) {
      setDisplayValue(value.toString());
    }
  };
  
  const handleChange = (e) => {
    const input = e.target.value;
    if (/^-?[\d,]*\.?\d*$/.test(input) || input === '') {
      setDisplayValue(input);
    }
  };
  
  const handleBlur = () => {
    const numValue = parseValue(displayValue);
    onChange(numValue);
    setDisplayValue(formatForDisplay(numValue));
  };
  
  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.target.blur();
    }
  };
  
  return (
    <input
      ref={inputRef}
      type="text"
      inputMode="decimal"
      value={displayValue}
      onChange={handleChange}
      onFocus={handleFocus}
      onBlur={handleBlur}
      onKeyDown={handleKeyDown}
      placeholder={placeholder}
      disabled={disabled}
      className={className}
    />
  );
};

