// Utility functions
const formatCurrency = (amount) => {
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 0, maximumFractionDigits: 0 }).format(amount || 0);
};

const formatDate = (dateStr) => {
  return new Date(dateStr).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
};

// Calculate totals
const calculateTotals = (bs) => {
  if (!bs) return {};
  
  // Current Assets
  const cashTotal = bs.currentAssets?.cash?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0;
  const arTotal = bs.currentAssets?.accountsReceivable?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0;
  const commodityTotal = bs.currentAssets?.commodityAccounts?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0;
  const cropInvTotal = bs.currentAssets?.cropInventory?.reduce((sum, i) => sum + (i.totalValue || i.amount || 0), 0) || 0;
  const feedInvTotal = bs.currentAssets?.feedInventory?.reduce((sum, i) => sum + (i.totalValue || i.amount || 0), 0) || 0;
  const marketLivestockTotal = bs.currentAssets?.marketLivestock?.reduce((sum, i) => sum + (i.totalValue || i.amount || 0), 0) || 0;
  const growingCropTotal = bs.currentAssets?.growingCrop?.reduce((sum, i) => sum + (i.totalValue || i.amount || 0), 0) || 0;
  const prepaidTotal = bs.currentAssets?.prepaidExpenses?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0;
  const otherCurrentTotal = bs.currentAssets?.otherCurrentAssets?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0;
  
  const currentAssetsTotal = cashTotal + arTotal + commodityTotal + cropInvTotal + feedInvTotal + 
    marketLivestockTotal + growingCropTotal + prepaidTotal + otherCurrentTotal;

  // Intermediate Assets
  const machineryTotal = bs.intermediateAssets?.machinery?.reduce((sum, i) => sum + (i.currentValue || 0), 0) || 0;
  const vehiclesTotal = bs.intermediateAssets?.vehicles?.reduce((sum, i) => sum + (i.currentValue || 0), 0) || 0;
  const breedingLivestockTotal = bs.intermediateAssets?.breedingLivestock?.reduce((sum, i) => sum + (i.totalValue || 0), 0) || 0;
  
  const intermediateAssetsTotal = machineryTotal + vehiclesTotal + breedingLivestockTotal;

  // Long-Term Assets
  const realEstateTotal = bs.longTermAssets?.realEstate?.reduce((sum, i) => sum + (i.marketValue || i.value || 0), 0) || 0;
  const buildingsTotal = bs.longTermAssets?.buildings?.reduce((sum, i) => sum + (i.currentValue || 0), 0) || 0;
  const otherLongTermTotal = bs.longTermAssets?.otherLongTerm?.reduce((sum, i) => sum + (i.currentValue || i.amount || 0), 0) || 0;
  
  const longTermAssetsTotal = realEstateTotal + buildingsTotal + otherLongTermTotal;

  const totalAssets = currentAssetsTotal + intermediateAssetsTotal + longTermAssetsTotal;

  // Current Liabilities
  const accountsPayableTotal = Array.isArray(bs.currentLiabilities?.accountsPayable) 
    ? bs.currentLiabilities.accountsPayable.reduce((sum, i) => sum + (i.amount || 0), 0) 
    : (bs.currentLiabilities?.accountsPayable || 0);
  const outstandingChecksTotal = Array.isArray(bs.currentLiabilities?.outstandingChecks)
    ? bs.currentLiabilities.outstandingChecks.reduce((sum, i) => sum + (i.amount || 0), 0)
    : (bs.currentLiabilities?.outstandingChecks || 0);
  const creditCardDebtTotal = Array.isArray(bs.currentLiabilities?.creditCardDebt)
    ? bs.currentLiabilities.creditCardDebt.reduce((sum, i) => sum + (i.amount || 0), 0)
    : (bs.currentLiabilities?.creditCardDebt || 0);
  
  // Calculate current portion term debt and accrued interest from debt service
  const debtServiceItems = bs.debtService || [];
  const calcCurrentPortionTermDebt = debtServiceItems
    .filter(d => d.category !== 'operating')
    .reduce((sum, d) => sum + (d.principalPayment || 0), 0);
  const calcAccruedInterest = debtServiceItems
    .reduce((sum, d) => sum + (d.accruedInterest || 0), 0);
    
  const currentLiabilitiesTotal = 
    accountsPayableTotal +
    outstandingChecksTotal +
    creditCardDebtTotal +
    (bs.currentLiabilities?.operatingLine || 0) +
    calcCurrentPortionTermDebt +
    calcAccruedInterest +
    (bs.currentLiabilities?.otherCurrentLiabilities?.reduce((sum, i) => sum + (i.amount || 0), 0) || 0);

  // Term Debt by Category (from debtService non-operating items)
  const termDebtFromDS = debtServiceItems.filter(d => d.category !== 'operating');
  const equipmentDebtTotal = termDebtFromDS.filter(d => d.category === 'equipment').reduce((sum, d) => sum + (d.principalAmount || 0), 0);
  const realEstateDebtTotal = termDebtFromDS.filter(d => d.category === 'realEstate').reduce((sum, d) => sum + (d.principalAmount || 0), 0);
  const vehicleDebtTotal = termDebtFromDS.filter(d => d.category === 'vehicle').reduce((sum, d) => sum + (d.principalAmount || 0), 0);
  const otherDebtTotal = termDebtFromDS.filter(d => d.category === 'other' || d.category === 'personal').reduce((sum, d) => sum + (d.principalAmount || 0), 0);
  
  // Non-current liabilities from debt service (principal - current year principal payment)
  // Intermediate = equipment + vehicle debt (non-current portion)
  // Long-term = real estate debt (non-current portion)
  const debtServiceByCategory = {
    equipment: debtServiceItems.filter(d => d.category === 'equipment'),
    vehicle: debtServiceItems.filter(d => d.category === 'vehicle'),
    realEstate: debtServiceItems.filter(d => d.category === 'realEstate'),
    other: debtServiceItems.filter(d => d.category === 'other' || d.category === 'personal')
  };
  
  // Calculate non-current portion (principal amount - principal payment for the year)
  const intermediateDebtNonCurrent = 
    debtServiceByCategory.equipment.reduce((sum, d) => sum + ((d.principalAmount || 0) - (d.principalPayment || 0)), 0) +
    debtServiceByCategory.vehicle.reduce((sum, d) => sum + ((d.principalAmount || 0) - (d.principalPayment || 0)), 0);
  
  const longTermDebtNonCurrent = 
    debtServiceByCategory.realEstate.reduce((sum, d) => sum + ((d.principalAmount || 0) - (d.principalPayment || 0)), 0);
  
  const otherTermDebtNonCurrent = 
    debtServiceByCategory.other.reduce((sum, d) => sum + ((d.principalAmount || 0) - (d.principalPayment || 0)), 0);
  
  const termDebtTotal = debtServiceItems.filter(d => d.category !== 'operating').reduce((sum, d) => sum + (d.principalAmount || 0), 0) || (bs.termDebt?.reduce((sum, i) => sum + (i.principal || 0), 0) || 0);
  const totalLiabilities = currentLiabilitiesTotal + termDebtTotal;
  const totalEquity = totalAssets - totalLiabilities;
  const workingCapital = currentAssetsTotal - currentLiabilitiesTotal;

  // Depreciation totals
  const machineryDepreciation = bs.intermediateAssets?.machinery?.reduce((sum, i) => sum + ((i.priorValue || 0) * (i.depRate || 0.1)), 0) || 0;
  const vehicleDepreciation = bs.intermediateAssets?.vehicles?.reduce((sum, i) => sum + ((i.priorValue || 0) * (i.depRate || 0.1)), 0) || 0;
  const buildingDepreciation = bs.longTermAssets?.buildings?.reduce((sum, i) => sum + ((i.priorValue || 0) * (i.depRate || 0.1)), 0) || 0;
  const totalDepreciation = machineryDepreciation + vehicleDepreciation + buildingDepreciation;

  return {
    // Current Assets breakdown
    cashTotal,
    arTotal,
    commodityTotal,
    cropInvTotal,
    feedInvTotal,
    marketLivestockTotal,
    growingCropTotal,
    prepaidTotal,
    otherCurrentTotal,
    currentAssetsTotal,
    // Intermediate Assets breakdown
    machineryTotal,
    vehiclesTotal,
    breedingLivestockTotal,
    intermediateAssetsTotal,
    // Long-Term Assets breakdown
    realEstateTotal,
    buildingsTotal,
    otherLongTermTotal,
    longTermAssetsTotal,
    // Total Assets
    totalAssets,
    // Current Liabilities breakdown
    apTotal: accountsPayableTotal,
    checksTotal: outstandingChecksTotal,
    ccTotal: creditCardDebtTotal,
    currentPortionTermDebt: calcCurrentPortionTermDebt,
    accruedInterest: calcAccruedInterest,
    // Liabilities
    currentLiabilitiesTotal,
    equipmentDebtTotal,
    realEstateDebtTotal,
    vehicleDebtTotal,
    otherDebtTotal,
    termDebtTotal,
    // Non-current debt by classification (for summary boxes)
    intermediateDebtNonCurrent,
    longTermDebtNonCurrent,
    otherTermDebtNonCurrent,
    totalLiabilities,
    // Equity & Ratios
    totalEquity,
    workingCapital,
    currentRatio: currentLiabilitiesTotal > 0 ? currentAssetsTotal / currentLiabilitiesTotal : 0,
    debtToEquity: totalEquity > 0 ? totalLiabilities / totalEquity : 0,
    equityPercent: totalAssets > 0 ? totalEquity / totalAssets : 0,
    debtToAssets: totalAssets > 0 ? totalLiabilities / totalAssets : 0,
    // Depreciation
    machineryDepreciation,
    vehicleDepreciation,
    buildingDepreciation,
    totalDepreciation
  };
};

// Collapsible Section Component
const CollapsibleSection = ({ title, icon: Icon, children, defaultOpen = false, total, color = 'blue' }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  
  const colorClasses = {
    blue: 'text-blue-600',
    green: 'text-green-600',
    amber: 'text-amber-600',
    purple: 'text-purple-600',
    red: 'text-red-600'
  };
  
  return (
    <div className="border border-gray-200 rounded-lg mb-3 bg-white">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between p-3 hover:bg-gray-50 transition-colors"
      >
        <div className="flex items-center gap-2">
          {isOpen ? <ChevronDown className="w-4 h-4 text-gray-500" /> : <ChevronRight className="w-4 h-4 text-gray-500" />}
          {Icon && <Icon className={`w-5 h-5 ${colorClasses[color]}`} />}
          <span className="font-semibold text-gray-800">{title}</span>
        </div>
        {total !== undefined && (
          <span className="font-mono text-sm font-semibold text-gray-700">{formatCurrency(total)}</span>
        )}
      </button>
      {isOpen && <div className="p-3 pt-0 border-t border-gray-100">{children}</div>}
    </div>
  );
};

// Editable Line Item
const LineItem = ({ item, onUpdate, onDelete, fields }) => {
  return (
    <div className="flex items-center gap-2 py-2 border-b border-gray-100 last:border-0">
      {fields.map((field) => (
        <div key={field.key} className={`${field.width || 'flex-1'} ${field.type === 'currency' ? 'flex items-center' : ''}`}>
          {field.type === 'currency' ? (
            <>
              <span className="text-gray-500 mr-1 flex-shrink-0">$</span>
              <CurrencyInput
                value={item[field.key] || 0}
                onChange={(val) => onUpdate({ ...item, [field.key]: val })}
                placeholder={field.placeholder}
                className="w-full px-2 py-1 text-sm border border-gray-200 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 text-right font-mono"
              />
            </>
          ) : (
            <input
              type={field.type || 'text'}
              value={item[field.key] || ''}
              onChange={(e) => {
                if (field.type === 'number') {
                  onUpdate({ ...item, [field.key]: parseFloat(e.target.value) || 0 });
                } else {
                  onUpdate({ ...item, [field.key]: e.target.value });
                }
              }}
              placeholder={field.placeholder}
              className={`w-full px-2 py-1 text-sm border border-gray-200 rounded focus:outline-none focus:ring-1 focus:ring-blue-500 ${field.type === 'number' ? 'text-right font-mono' : ''}`}
            />
          )}
        </div>
      ))}
      <button onClick={onDelete} className="p-1 text-red-500 hover:bg-red-50 rounded flex-shrink-0">
        <Trash2 className="w-4 h-4" />
      </button>
    </div>
  );
};

