// Depreciation Schedule Component (Machinery & Vehicles)
const DepreciationSchedule = ({ 
  items, onUpdate, onAdd, onDelete, onBulkUpdate, title, icon, color = 'amber',
  // Optional capital activity props
  purchases, sales, onAddPurchase, onUpdatePurchase, onDeletePurchase, onAddSale, onUpdateSale, onDeleteSale,
  // Optional: add purchase to asset inventory
  onAddAssetFromPurchase
}) => {
  const [showCapitalActivity, setShowCapitalActivity] = useState(false);
  const [showAssetPasteModal, setShowAssetPasteModal] = useState(false);
  const [assetPasteColumn, setAssetPasteColumn] = useState('');
  const [assetPasteData, setAssetPasteData] = useState('');
  const totalPurchases = purchases?.reduce((s, p) => s + (p.totalCost || 0), 0) || 0;
  const totalSales = sales?.reduce((s, p) => s + (p.salePrice || 0), 0) || 0;
  const totalGainLoss = sales?.reduce((s, p) => s + (p.gainLoss || 0), 0) || 0;
  const hasCapitalActivity = onAddPurchase && onAddSale;
  
  // Calculate totals excluding sold items
  const activeItems = items?.filter(i => !i.sold) || [];
  const soldItems = items?.filter(i => i.sold) || [];
  const totalSoldGainLoss = soldItems.reduce((s, i) => s + ((i.salePrice || 0) - (i.priorValue || 0)), 0);

  // Check if a purchase is already linked to an asset
  const isPurchaseLinkedToAsset = (purchaseId) => {
    return items?.some(i => i.linkedPurchaseId === purchaseId);
  };

  // Helper to sync sold item to capital activity sales
  const syncToCapitalSales = (item, isSelling) => {
    if (!onAddSale || !onUpdateSale || !onDeleteSale) return;
    
    const saleId = `sale-from-${item.id}`;
    const existingSale = sales?.find(s => s.id === saleId);
    
    if (isSelling) {
      const saleEntry = {
        id: saleId,
        description: item.description || '',
        previousValue: item.priorValue || 0,
        salePrice: item.salePrice || item.currentValue || 0,
        gainLoss: (item.salePrice || item.currentValue || 0) - (item.priorValue || 0),
        saleDate: item.saleDate || new Date().toISOString().slice(0, 10),
        linkedAssetId: item.id
      };
      
      if (existingSale) {
        onUpdateSale(saleEntry);
      } else {
        // We need to add a new sale - use onAddSale but it creates blank, so we update after
        onUpdateSale(saleEntry);
      }
    } else {
      // Remove from sales when unchecked
      if (existingSale) {
        onDeleteSale(saleId);
      }
    }
  };

  // Handle sold checkbox change
  const handleSoldChange = (item, isSold) => {
    const updatedItem = {
      ...item,
      sold: isSold,
      salePrice: isSold ? (item.salePrice || item.currentValue || 0) : 0,
      saleDate: isSold ? (item.saleDate || new Date().toISOString().slice(0, 10)) : ''
    };
    
    onUpdate(updatedItem);
    
    // Sync to capital activity
    if (isSold) {
      syncToCapitalSales(updatedItem, true);
    } else {
      syncToCapitalSales(item, false);
    }
  };

  // Handle sale price/date changes
  const handleSaleDetailChange = (item, field, value) => {
    const updatedItem = { ...item, [field]: value };
    onUpdate(updatedItem);
    
    // Also update the capital activity sale
    if (item.sold && onUpdateSale) {
      const saleId = `sale-from-${item.id}`;
      const gainLoss = (field === 'salePrice' ? value : item.salePrice || 0) - (item.priorValue || 0);
      onUpdateSale({
        id: saleId,
        description: item.description || '',
        previousValue: item.priorValue || 0,
        salePrice: field === 'salePrice' ? value : (item.salePrice || 0),
        gainLoss: gainLoss,
        saleDate: field === 'saleDate' ? value : (item.saleDate || ''),
        linkedAssetId: item.id
      });
    }
  };

  return (
    <CollapsibleSection 
      title={title} 
      icon={icon}
      color={color}
      total={activeItems.reduce((sum, i) => sum + (i.currentValue || 0), 0)}
    >
      <div className="overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="text-left text-gray-600 border-b">
              <th className="pb-2 font-medium w-10 text-center">Sold</th>
              <th className="pb-2 font-medium">Description</th>
              <th className="pb-2 font-medium w-24">Enterprise</th>
              <th className="pb-2 font-medium w-12 text-center">Qty</th>
              <th className="pb-2 font-medium w-20 text-center">Condition</th>
              <th className="pb-2 font-medium w-16 text-center">Year</th>
              <th className="pb-2 font-medium w-24">Serial #</th>
              <th className="pb-2 font-medium w-24 text-center">Date Acq</th>
              <th className="pb-2 font-medium w-28 text-right">Value</th>
              <th className="pb-2 font-medium w-14 text-right">Dep%</th>
              <th className="pb-2 font-medium w-24 text-right">Depreciation</th>
              <th className="pb-2 font-medium w-28 text-right">Bal Value</th>
              <th className="pb-2 w-10"></th>
            </tr>
          </thead>
          <tbody>
            {items?.map((item) => (
              <React.Fragment key={item.id}>
                <tr className={`border-b border-gray-50 ${item.sold ? 'bg-amber-50' : ''}`}>
                  <td className="py-2 text-center">
                    <input
                      type="checkbox"
                      checked={item.sold || false}
                      onChange={(e) => handleSoldChange(item, e.target.checked)}
                      className="w-4 h-4 text-amber-600 rounded border-gray-300 focus:ring-amber-500 cursor-pointer"
                    />
                  </td>
                  <td className="py-2">
                    <input
                      type="text"
                      value={item.description || ''}
                      onChange={(e) => onUpdate({ ...item, description: e.target.value })}
                      className={`w-full px-2 py-1 border border-gray-200 rounded text-sm ${item.sold ? 'bg-amber-50 line-through text-gray-500' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <input
                      type="text"
                      value={item.enterprise || ''}
                      onChange={(e) => onUpdate({ ...item, enterprise: e.target.value })}
                      placeholder="Enterprise"
                      disabled={item.sold}
                      className={`w-full px-2 py-1 border border-gray-200 rounded text-sm ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <input
                      type="number"
                      value={item.quantity || 1}
                      onChange={(e) => onUpdate({ ...item, quantity: parseInt(e.target.value) || 1 })}
                      disabled={item.sold}
                      className={`w-full px-1 py-1 border border-gray-200 rounded text-sm text-center ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <select
                      value={item.condition || 'Good'}
                      onChange={(e) => onUpdate({ ...item, condition: e.target.value })}
                      disabled={item.sold}
                      className={`w-full px-1 py-1 border border-gray-200 rounded text-sm text-center ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    >
                      <option value="New">New</option>
                      <option value="Excellent">Excellent</option>
                      <option value="Good">Good</option>
                      <option value="Fair">Fair</option>
                      <option value="Poor">Poor</option>
                    </select>
                  </td>
                  <td className="py-2">
                    <input
                      type="number"
                      value={item.year || ''}
                      onChange={(e) => onUpdate({ ...item, year: parseInt(e.target.value) || '' })}
                      placeholder="YYYY"
                      disabled={item.sold}
                      className={`w-full px-1 py-1 border border-gray-200 rounded text-sm text-center ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <input
                      type="text"
                      value={item.serial || ''}
                      onChange={(e) => onUpdate({ ...item, serial: e.target.value })}
                      placeholder="Serial #"
                      disabled={item.sold}
                      className={`w-full px-2 py-1 border border-gray-200 rounded text-sm ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <input
                      type="date"
                      value={item.dateAcquired || ''}
                      onChange={(e) => onUpdate({ ...item, dateAcquired: e.target.value })}
                      disabled={item.sold}
                      className={`w-full px-1 py-1 border border-gray-200 rounded text-sm ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className="py-2">
                    <div className="flex items-center">
                      <span className="text-gray-500 mr-1">$</span>
                      <CurrencyInput
                        value={item.priorValue || 0}
                        onChange={(val) => {
                          const depRate = item.depRate || 0.1;
                          onUpdate({ ...item, priorValue: val, currentValue: val * (1 - depRate) });
                        }}
                        disabled={item.sold}
                        className={`w-full px-2 py-1 border border-gray-200 rounded text-sm text-right font-mono ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                      />
                    </div>
                  </td>
                  <td className="py-2">
                    <input
                      type="number"
                      value={((item.depRate || 0.1) * 100)}
                      onChange={(e) => {
                        const newRate = parseFloat(e.target.value) / 100 || 0.1;
                        onUpdate({ 
                          ...item, 
                          depRate: newRate,
                          currentValue: (item.priorValue || 0) * (1 - newRate)
                        });
                      }}
                      disabled={item.sold}
                      className={`w-full px-1 py-1 border border-gray-200 rounded text-sm text-right ${item.sold ? 'bg-gray-100 text-gray-400' : ''}`}
                    />
                  </td>
                  <td className={`py-2 text-right font-mono ${item.sold ? 'text-gray-400' : 'text-red-600'}`}>
                    {item.sold ? '—' : `($${((item.priorValue || 0) * (item.depRate || 0.1)).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })})`}
                  </td>
                  <td className="py-2">
                    <div className="flex items-center">
                      <span className="text-gray-500 mr-1">$</span>
                      <CurrencyInput
                        value={item.sold ? 0 : (item.currentValue || 0)}
                        onChange={(val) => onUpdate({ ...item, currentValue: val })}
                        disabled={item.sold}
                        className={`w-full px-2 py-1 border border-gray-200 rounded text-sm text-right font-mono ${item.sold ? 'bg-gray-100 text-gray-400' : 'bg-gray-50'}`}
                      />
                    </div>
                  </td>
                  <td className="py-2">
                    <button onClick={() => onDelete(item.id)} className="p-1 text-red-500 hover:bg-red-50 rounded">
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
                {/* Sold Details Row */}
                {item.sold && (
                  <tr className="bg-amber-100 border-b border-amber-200">
                    <td colSpan="13" className="py-3 px-4">
                      <div className="flex items-center gap-6 flex-wrap">
                        <div className="flex items-center gap-2">
                          <span className="text-sm font-medium text-amber-800">Sale Date:</span>
                          <input
                            type="date"
                            value={item.saleDate || ''}
                            onChange={(e) => handleSaleDetailChange(item, 'saleDate', e.target.value)}
                            className="px-2 py-1 border border-amber-300 rounded text-sm bg-white"
                          />
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="text-sm font-medium text-amber-800">Sale Price:</span>
                          <div className="flex items-center">
                            <span className="text-amber-600 mr-1">$</span>
                            <CurrencyInput
                              value={item.salePrice || 0}
                              onChange={(val) => handleSaleDetailChange(item, 'salePrice', val)}
                              className="w-32 px-2 py-1 border border-amber-300 rounded text-sm text-right font-mono bg-white"
                            />
                          </div>
                        </div>
                        <div className="flex items-center gap-2">
                          <span className="text-sm font-medium text-amber-800">Book Value:</span>
                          <span className="font-mono text-sm">${(item.priorValue || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}</span>
                        </div>
                        <div className="flex items-center gap-3 ml-auto bg-white rounded-lg px-4 py-2 border border-amber-300">
                          <span className="text-sm font-semibold text-amber-900">
                            {(item.salePrice || 0) >= (item.priorValue || 0) ? 'Gain:' : 'Loss:'}
                          </span>
                          <span className={`font-mono font-bold text-lg ${(item.salePrice || 0) >= (item.priorValue || 0) ? 'text-green-600' : 'text-red-600'}`}>
                            {(item.salePrice || 0) >= (item.priorValue || 0) ? '+' : ''}
                            ${((item.salePrice || 0) - (item.priorValue || 0)).toLocaleString('en-US', { minimumFractionDigits: 2 })}
                          </span>
                        </div>
                        <div className="text-xs text-amber-700 bg-amber-200 px-2 py-1 rounded">
                          ✓ Synced to Capital Activity
                        </div>
                      </div>
                    </td>
                  </tr>
                )}
              </React.Fragment>
            ))}
          </tbody>
          <tfoot>
            {/* Enterprise Summary */}
            {(() => {
              const enterprises = [...new Set(activeItems.map(i => i.enterprise || 'Unassigned'))].sort();
              if (enterprises.length > 1 || (enterprises.length === 1 && enterprises[0] !== 'Unassigned')) {
                return enterprises.map(ent => {
                  const entItems = activeItems.filter(i => (i.enterprise || 'Unassigned') === ent);
                  const entValue = entItems.reduce((s, i) => s + (i.priorValue || 0), 0);
                  const entDep = entItems.reduce((s, i) => s + ((i.priorValue || 0) * (i.depRate || 0.1)), 0);
                  const entBal = entItems.reduce((s, i) => s + (i.currentValue || 0), 0);
                  return (
                    <tr key={ent} className="bg-blue-50 text-blue-800 border-b border-blue-100">
                      <td className="py-1 px-2"></td>
                      <td colSpan="6" className="py-1 px-2 font-medium">{ent}</td>
                      <td className="py-1 text-right font-mono text-sm">${entValue.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                      <td></td>
                      <td className="py-1 text-right font-mono text-sm text-red-600">
                        (${entDep.toLocaleString('en-US', { minimumFractionDigits: 2 })})
                      </td>
                      <td className="py-1 text-right font-mono text-sm">${entBal.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                      <td></td>
                    </tr>
                  );
                });
              }
              return null;
            })()}
            {/* Active Items Total */}
            <tr className="font-semibold bg-gray-50">
              <td className="py-2 px-2"></td>
              <td colSpan="6" className="py-2 px-2">Active Items Total</td>
              <td className="py-2 text-right font-mono">${(activeItems.reduce((s, i) => s + (i.priorValue || 0), 0)).toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
              <td></td>
              <td className="py-2 text-right font-mono text-red-600">
                (${(activeItems.reduce((s, i) => s + ((i.priorValue || 0) * (i.depRate || 0.1)), 0)).toLocaleString('en-US', { minimumFractionDigits: 2 })})
              </td>
              <td className="py-2 text-right font-mono">${(activeItems.reduce((s, i) => s + (i.currentValue || 0), 0)).toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
              <td></td>
            </tr>
            {/* Sold Items Summary */}
            {soldItems.length > 0 && (
              <tr className="font-semibold bg-amber-50 text-amber-800">
                <td className="py-2 px-2"></td>
                <td colSpan="6" className="py-2 px-2">
                  Sold Items ({soldItems.length}) — Total Sales: ${soldItems.reduce((s, i) => s + (i.salePrice || 0), 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}
                </td>
                <td colSpan="3" className="py-2 text-right">
                  Book Value: ${soldItems.reduce((s, i) => s + (i.priorValue || 0), 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}
                </td>
                <td className={`py-2 text-right font-mono ${totalSoldGainLoss >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                  {totalSoldGainLoss >= 0 ? 'Gain: +' : 'Loss: '}${Math.abs(totalSoldGainLoss).toLocaleString('en-US', { minimumFractionDigits: 2 })}
                </td>
                <td></td>
              </tr>
            )}
          </tfoot>
        </table>
      </div>
      <div className="mt-3 flex items-center gap-3">
        <button
          onClick={onAdd}
          className="flex items-center gap-1 text-sm text-blue-600 hover:text-blue-800"
        >
          <Plus className="w-4 h-4" /> Add Item
        </button>
        <button
          onClick={() => setShowAssetPasteModal(true)}
          className="flex items-center gap-1 text-sm text-purple-600 hover:text-purple-800"
        >
          <ClipboardList className="w-4 h-4" /> Paste Columns
        </button>
      </div>

      {/* Paste Columns Modal */}
      {showAssetPasteModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-2xl w-full max-h-[90vh] overflow-hidden">
            <div className="px-6 py-4 border-b border-gray-200 flex items-center justify-between">
              <h3 className="text-lg font-bold text-gray-800">Paste {title} Data from Excel</h3>
              <button onClick={() => { setShowAssetPasteModal(false); setAssetPasteData(''); setAssetPasteColumn(''); }} className="p-2 hover:bg-gray-100 rounded-lg"><X className="w-5 h-5" /></button>
            </div>
            <div className="p-6 space-y-4">
              <div className="bg-purple-50 border border-purple-200 rounded-lg p-4">
                <p className="text-sm text-purple-700"><strong>How to use:</strong> Copy a column from Excel, select which field to paste into, paste below, then click Apply. Data applies to existing rows in order; extra rows create new items.</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Select Column to Paste Into</label>
                <select value={assetPasteColumn} onChange={(e) => setAssetPasteColumn(e.target.value)} className="w-full px-3 py-2 border border-gray-300 rounded-lg">
                  <option value="">Select a column...</option>
                  <option value="description">Description</option>
                  <option value="enterprise">Enterprise</option>
                  <option value="quantity">Quantity</option>
                  <option value="condition">Condition</option>
                  <option value="year">Year</option>
                  <option value="serialNumber">Serial #</option>
                  <option value="dateAcquired">Date Acquired</option>
                  <option value="currentValue">Value</option>
                  <option value="depRate">Depreciation Rate (%)</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Paste Data Here <span className="text-gray-400 font-normal ml-2">({assetPasteData ? assetPasteData.split('\n').filter(l => l.trim()).length : 0} rows)</span></label>
                <textarea value={assetPasteData} onChange={(e) => setAssetPasteData(e.target.value)} placeholder="Paste column data from Excel here..." className="w-full h-48 px-3 py-2 border border-gray-300 rounded-lg font-mono text-sm resize-none" />
              </div>
            </div>
            <div className="px-6 py-4 border-t border-gray-200 flex justify-end gap-3">
              <button onClick={() => { setShowAssetPasteModal(false); setAssetPasteData(''); setAssetPasteColumn(''); }} className="px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50">Cancel</button>
              <button
                onClick={() => {
                  if (!assetPasteColumn || !assetPasteData.trim() || !onBulkUpdate) return;
                  const lines = assetPasteData.split('\n').map(l => l.trim()).filter(l => l);
                  const existing = [...(items || [])];
                  lines.forEach((value, idx) => {
                    let parsed = value;
                    if (assetPasteColumn === 'currentValue' || assetPasteColumn === 'quantity') {
                      parsed = parseFloat(value.replace(/[^0-9.-]/g, '')) || 0;
                    } else if (assetPasteColumn === 'depRate') {
                      const num = parseFloat(value.replace(/[^0-9.-]/g, '')) || 0;
                      parsed = num > 1 ? num / 100 : num;
                    } else if (assetPasteColumn === 'year') {
                      parsed = parseInt(value.replace(/[^0-9]/g, '')) || '';
                    }
                    if (idx < existing.length) {
                      existing[idx] = { ...existing[idx], [assetPasteColumn]: parsed };
                    } else {
                      existing.push({
                        id: `asset-${Date.now()}-${idx}-${Math.random().toString(36).substr(2, 5)}`,
                        description: '', quantity: 1, condition: 'Good', year: new Date().getFullYear(),
                        serial: '', dateAcquired: '', priorValue: 0, currentValue: 0, depRate: 0.10,
                        [assetPasteColumn]: parsed,
                      });
                    }
                  });
                  onBulkUpdate(existing);
                  setShowAssetPasteModal(false); setAssetPasteData(''); setAssetPasteColumn('');
                }}
                disabled={!assetPasteColumn || !assetPasteData.trim()}
                className="px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 disabled:opacity-50 disabled:cursor-not-allowed"
              >Apply to {assetPasteData ? assetPasteData.split('\n').filter(l => l.trim()).length : 0} Rows</button>
            </div>
          </div>
        </div>
      )}

      {/* Capital Activity Section - Inside the collapsible */}
      {hasCapitalActivity && (
        <div className="mt-4 border-t border-gray-200 pt-4">
          <button
            onClick={() => setShowCapitalActivity(!showCapitalActivity)}
            className="flex items-center gap-2 text-sm font-medium text-gray-700 hover:text-gray-900"
          >
            {showCapitalActivity ? <ChevronDown className="w-4 h-4" /> : <ChevronRight className="w-4 h-4" />}
            <TrendingUp className="w-4 h-4 text-purple-600" />
            Capital Activity
            <span className="text-xs text-gray-500 ml-2">
              (Purchases: ${totalPurchases.toLocaleString()} | Sales: ${totalSales.toLocaleString()})
            </span>
          </button>
          
          {showCapitalActivity && (
            <div className="mt-3 space-y-4 pl-6">
              {/* Purchases Section */}
              <div className="bg-green-50 rounded-lg p-4">
                <h4 className="font-medium text-green-800 mb-2 flex items-center gap-2">
                  <Plus className="w-4 h-4" /> Purchases
                </h4>
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left text-green-700 border-b border-green-200">
                      <th className="pb-2 font-medium">Description</th>
                      <th className="pb-2 font-medium w-28 text-right">Cash Paid</th>
                      <th className="pb-2 font-medium w-28 text-right">Financed</th>
                      <th className="pb-2 font-medium w-28 text-right">Total Cost</th>
                      {onAddAssetFromPurchase && <th className="pb-2 font-medium w-28 text-center">Add to Inventory</th>}
                      <th className="pb-2 w-10"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {purchases?.map(item => {
                      const isLinkedToAsset = isPurchaseLinkedToAsset(item.id);
                      return (
                      <tr key={item.id} className={`border-b border-green-100 ${isLinkedToAsset ? 'bg-blue-50' : ''}`}>
                        <td className="py-2">
                          <div className="flex items-center gap-2">
                            {isLinkedToAsset && (
                              <span className="text-xs bg-blue-200 text-blue-800 px-1.5 py-0.5 rounded" title="Added to inventory above">
                                ↑
                              </span>
                            )}
                            <input
                              type="text"
                              value={item.description || ''}
                              onChange={(e) => onUpdatePurchase({ ...item, description: e.target.value })}
                              className={`w-full px-2 py-1 border border-green-200 rounded text-sm ${isLinkedToAsset ? 'bg-blue-50' : ''}`}
                              placeholder="Item description"
                            />
                          </div>
                        </td>
                        <td className="py-2">
                          <div className="flex items-center">
                            <span className="text-gray-500 mr-1">$</span>
                            <CurrencyInput
                              value={item.cashPaid || 0}
                              onChange={(val) => {
                                onUpdatePurchase({ ...item, cashPaid: val, totalCost: val + (item.financedAmount || 0) });
                              }}
                              className="w-full px-2 py-1 border border-green-200 rounded text-sm text-right font-mono"
                            />
                          </div>
                        </td>
                        <td className="py-2">
                          <div className="flex items-center">
                            <span className="text-gray-500 mr-1">$</span>
                            <CurrencyInput
                              value={item.financedAmount || 0}
                              onChange={(val) => {
                                onUpdatePurchase({ ...item, financedAmount: val, totalCost: (item.cashPaid || 0) + val });
                              }}
                              className="w-full px-2 py-1 border border-green-200 rounded text-sm text-right font-mono"
                            />
                          </div>
                        </td>
                        <td className="py-2 text-right font-mono font-semibold text-green-700">
                          ${(item.totalCost || 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}
                        </td>
                        {onAddAssetFromPurchase && (
                          <td className="py-2 text-center">
                            {isLinkedToAsset ? (
                              <span className="text-xs text-blue-600 bg-blue-100 px-2 py-1 rounded">
                                ✓ In Inventory
                              </span>
                            ) : (
                              <button
                                onClick={() => onAddAssetFromPurchase(item)}
                                disabled={!item.description || !item.totalCost}
                                className={`text-xs px-2 py-1 rounded flex items-center gap-1 mx-auto ${
                                  item.description && item.totalCost 
                                    ? 'bg-blue-500 text-white hover:bg-blue-600' 
                                    : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                                }`}
                                title={!item.description || !item.totalCost ? 'Enter description and cost first' : 'Add to asset inventory above'}
                              >
                                <Plus className="w-3 h-3" /> Add ↑
                              </button>
                            )}
                          </td>
                        )}
                        <td className="py-2">
                          <button onClick={() => onDeletePurchase(item.id)} className="p-1 text-red-500 hover:bg-red-50 rounded">
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </td>
                      </tr>
                    )})}
                  </tbody>
                  {purchases?.length > 0 && (
                    <tfoot>
                      <tr className="font-semibold bg-green-100">
                        <td className="py-2 px-2">Total Purchases</td>
                        <td className="py-2 text-right font-mono">${purchases.reduce((s, p) => s + (p.cashPaid || 0), 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                        <td className="py-2 text-right font-mono">${purchases.reduce((s, p) => s + (p.financedAmount || 0), 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                        <td className="py-2 text-right font-mono text-green-700">${totalPurchases.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                        {onAddAssetFromPurchase && <td></td>}
                        <td></td>
                      </tr>
                    </tfoot>
                  )}
                </table>
                <button
                  onClick={onAddPurchase}
                  className="mt-2 text-sm text-green-600 hover:text-green-800 flex items-center gap-1"
                >
                  <Plus className="w-4 h-4" /> Add Purchase
                </button>
              </div>
              
              {/* Sales Section */}
              <div className="bg-orange-50 rounded-lg p-4">
                <h4 className="font-medium text-orange-800 mb-2 flex items-center gap-2">
                  <TrendingUp className="w-4 h-4" /> Sales / Trades
                </h4>
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left text-orange-700 border-b border-orange-200">
                      <th className="pb-2 font-medium">Description</th>
                      <th className="pb-2 font-medium w-28 text-right">Previous Value</th>
                      <th className="pb-2 font-medium w-28 text-right">Sale/Trade Price</th>
                      <th className="pb-2 font-medium w-28 text-right">Gain/(Loss)</th>
                      <th className="pb-2 w-10"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {sales?.map(item => {
                      const gainLoss = (item.salePrice || 0) - (item.previousValue || 0);
                      const isLinked = item.linkedAssetId || item.id?.startsWith('sale-from-');
                      return (
                        <tr key={item.id} className={`border-b border-orange-100 ${isLinked ? 'bg-amber-50' : ''}`}>
                          <td className="py-2">
                            <div className="flex items-center gap-2">
                              {isLinked && (
                                <span className="text-xs bg-amber-200 text-amber-800 px-1.5 py-0.5 rounded" title="Linked from asset list">
                                  ↑
                                </span>
                              )}
                              <input
                                type="text"
                                value={item.description || ''}
                                onChange={(e) => onUpdateSale({ ...item, description: e.target.value })}
                                className={`w-full px-2 py-1 border border-orange-200 rounded text-sm ${isLinked ? 'bg-amber-50' : ''}`}
                                placeholder="Item description"
                                readOnly={isLinked}
                              />
                            </div>
                          </td>
                          <td className="py-2">
                            <div className="flex items-center">
                              <span className="text-gray-500 mr-1">$</span>
                              <CurrencyInput
                                value={item.previousValue || 0}
                                onChange={(val) => {
                                  const gl = (item.salePrice || 0) - val;
                                  onUpdateSale({ ...item, previousValue: val, gainLoss: gl });
                                }}
                                disabled={isLinked}
                                className={`w-full px-2 py-1 border border-orange-200 rounded text-sm text-right font-mono ${isLinked ? 'bg-amber-50' : ''}`}
                              />
                            </div>
                          </td>
                          <td className="py-2">
                            <div className="flex items-center">
                              <span className="text-gray-500 mr-1">$</span>
                              <CurrencyInput
                                value={item.salePrice || 0}
                                onChange={(val) => {
                                  const gl = val - (item.previousValue || 0);
                                  onUpdateSale({ ...item, salePrice: val, gainLoss: gl });
                                }}
                                disabled={isLinked}
                                className={`w-full px-2 py-1 border border-orange-200 rounded text-sm text-right font-mono ${isLinked ? 'bg-amber-50' : ''}`}
                              />
                            </div>
                          </td>
                          <td className={`py-2 text-right font-mono font-semibold ${gainLoss >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                            {gainLoss >= 0 ? '' : '('}${Math.abs(gainLoss).toLocaleString('en-US', { minimumFractionDigits: 2 })}{gainLoss >= 0 ? '' : ')'}
                          </td>
                          <td className="py-2">
                            {isLinked ? (
                              <span className="text-xs text-amber-600" title="Uncheck 'Sold' on asset to remove">
                                🔗
                              </span>
                            ) : (
                              <button onClick={() => onDeleteSale(item.id)} className="p-1 text-red-500 hover:bg-red-50 rounded">
                                <Trash2 className="w-4 h-4" />
                              </button>
                            )}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                  {sales?.length > 0 && (
                    <tfoot>
                      <tr className="font-semibold bg-orange-100">
                        <td className="py-2 px-2">Total Sales</td>
                        <td className="py-2 text-right font-mono">${sales.reduce((s, p) => s + (p.previousValue || 0), 0).toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                        <td className="py-2 text-right font-mono">${totalSales.toLocaleString('en-US', { minimumFractionDigits: 2 })}</td>
                        <td className={`py-2 text-right font-mono font-semibold ${totalGainLoss >= 0 ? 'text-green-600' : 'text-red-600'}`}>
                          {totalGainLoss >= 0 ? '' : '('}${Math.abs(totalGainLoss).toLocaleString('en-US', { minimumFractionDigits: 2 })}{totalGainLoss >= 0 ? '' : ')'}
                        </td>
                        <td></td>
                      </tr>
                    </tfoot>
                  )}
                </table>
                <button
                  onClick={onAddSale}
                  className="mt-2 text-sm text-orange-600 hover:text-orange-800 flex items-center gap-1"
                >
                  <Plus className="w-4 h-4" /> Add Sale/Trade
                </button>
              </div>
            </div>
          )}
        </div>
      )}
    </CollapsibleSection>
  );
};

// Main App Component
