  // === PERSISTENT CLOUD STORAGE (window.storage) ===
  // Data persists across devices and sessions via window.storage API
  const dataLoaded = useRef(false);
  const [isLoadingData, setIsLoadingData] = useState(true);
  
  // Initialize with defaults - cloud data will override on mount
  const [clients, setClients] = useState(sampleClients);
