  const [cashFlowTab, setCashFlowTab] = useState('summary');
  const [selectedEnterprise, setSelectedEnterprise] = useState(null);
  const [activeEnterprises, setActiveEnterprises] = useState([]);
  const enterpriseLabelMap = { global: 'Global', rowCrop: 'Row Crop', cowCalf: 'Cow/Calf', custom: 'Custom Revenue', customFeeding: 'Custom Feeding', cattleFeeding: 'Cattle Feeding', dairy: 'Dairy', swine: 'Swine', personal: 'Personal' };
  const activeEnterpriseLabels = Object.entries(enterpriseLabelMap).filter(([k]) => k !== 'global').map(([, v]) => v).sort((a, b) => a.localeCompare(b));
  const [variableExpenseTab, setVariableExpenseTab] = useState('seed');
  const [cattleFeedingTab, setCattleFeedingTab] = useState('projection');
  const [cattleFeedingLots, setCattleFeedingLots] = useState([{
    id: 'lot-1', lotName: 'Lot 1 - Spring Steers', cattleType: 'Steers', headCount: 100,
    purchaseDate: '2025-03-15', purchaseWeight: 550, purchasePrice: 2.45,
    projectedSaleDate: '2025-09-15', projectedSaleWeight: 1350, projectedSalePrice: 1.95,
    daysOnFeed: 180, avgDailyGain: 3.5, deathLossPercent: 1.5, feedCostPerDay: 3.25,
    yardageCostPerDay: 0.50, vetHealthPerHead: 35, interestRate: 8.0,
    freightInPerHead: 15, freightOutPerHead: 25, commissionPerHead: 12, otherCostsPerHead: 10
  }]);
  const [cattleCloseouts, setCattleCloseouts] = useState([]);
  const [cattleFeedingLRP, setCattleFeedingLRP] = useState([]);

  // Load all data from persistent cloud storage on mount
  // Includes one-time migration from localStorage (old versions) to window.storage
  useEffect(() => {
    const loadAllData = async () => {
      if (!window.storage) {
        console.warn('window.storage not available, using defaults');
        dataLoaded.current = true;
        setIsLoadingData(false);
        return;
      }
      
      // Mapping of cloud storage keys to their old localStorage keys and fallback defaults
      const keys = [
        { key: 'farm-app-clients', localKey: 'farm-app-clients', setter: setClients, fallback: sampleClients },
        { key: 'farm-app-balancesheets', localKey: 'farm-app-balancesheets', setter: setBalanceSheets, fallback: sampleBalanceSheets },
        { key: 'farm-app-cattle-feeding-lots', localKey: 'farm-app-cattle-feeding-lots', setter: setCattleFeedingLots, fallback: null },
        { key: 'farm-app-cattle-closeouts', localKey: 'farm-app-cattle-closeouts', setter: setCattleCloseouts, fallback: null },
        { key: 'farm-app-cattle-feeding-lrp', localKey: 'farm-app-cattle-feeding-lrp', setter: setCattleFeedingLRP, fallback: null },
        { key: 'farm-app-transactions', localKey: 'transactionTrackerData', setter: setTransactions, fallback: null },
        { key: 'farm-app-import-presets', localKey: 'importPresets', setter: setImportPresets, fallback: null },
        { key: 'farm-app-earned-equity', localKey: 'earnedEquityData', setter: setEarnedEquityData, fallback: null },
        { key: 'farm-app-itemization-mappings', localKey: 'itemizationMappings', setter: setItemizationMappings, fallback: null },
        { key: 'farm-app-bank-reconciliation', localKey: 'bankReconciliationData', setter: setBankReconciliation, fallback: null },
        { key: 'farm-app-active-enterprises', localKey: 'activeEnterprises', setter: setActiveEnterprises, fallback: null },
        { key: 'farm-app-selected-enterprise', localKey: 'selectedEnterprise', setter: setSelectedEnterprise, fallback: null },
      ];
      
      try {
        let migratedCount = 0;
        
        for (const { key, localKey, setter, fallback } of keys) {
          let loaded = false;
          
          // Step 1: Try loading from cloud storage
          try {
            const result = await window.storage.get(key);
            if (result && result.value) {
              setter(JSON.parse(result.value));
              loaded = true;
            }
          } catch {
            // Key doesn't exist in cloud yet
          }
          
          // Step 2: If not in cloud, check localStorage for migration
          if (!loaded) {
            try {
              const localData = localStorage.getItem(localKey);
              if (localData) {
                const parsed = JSON.parse(localData);
                setter(parsed);
                // Migrate to cloud storage
                await window.storage.set(key, localData);
                migratedCount++;
                loaded = true;
              }
            } catch {
              // localStorage not available or parse error
            }
          }
          
          // Step 3: If still nothing, use fallback
          if (!loaded && fallback) {
            setter(fallback);
          }
        }
        
        if (migratedCount > 0) {
          console.log(`Migrated ${migratedCount} data stores from local storage to cloud storage.`);
        }
      } catch (e) {
        console.error('Error loading data from cloud storage:', e);
      }
      dataLoaded.current = true;
      setIsLoadingData(false);
    };
    loadAllData();
  }, []);

