                              <textarea value={realEstatePasteData} onChange={(e) => setRealEstatePasteData(e.target.value)} placeholder="Paste column data from Excel here..." className="w-full h-48 px-3 py-2 border border-gray-300 rounded-lg font-mono text-sm resize-none" />
