                                        const val = e.target.value.replace(/[^0-9]/g, '');
                                        const newCowCalf = { ...cowCalf };
                                        if (!newCowCalf.herd) newCowCalf.herd = {};
                                        if (!newCowCalf.herd[row.key]) newCowCalf.herd[row.key] = {};
                                        newCowCalf.herd[row.key] = { ...newCowCalf.herd[row.key], [m]: val };
                                        updateBS({ cashFlow: { ...(selectedBS?.cashFlow || {}), cowCalf: newCowCalf } });
