                      const totalProjected = months.reduce((s, m) => s + ((sizeScope[m]?.projected || 0)), 0);
                      const totalActual = months.reduce((s, m) => s + ((sizeScope[m]?.actual || 0)), 0);
                      const variance = totalProjected - totalActual;
                      const variancePercent = totalActual > 0 ? ((totalProjected - totalActual) / totalActual * 100) : 0;
                      
                      // Utilization
