                                  const monthVariancePercent = actual > 0 ? ((projected - actual) / actual * 100) : 0;
                                  const monthCapacity = yardCapacity * daysInMonth[idx];
                                  const monthUtilization = monthCapacity > 0 ? (projected / monthCapacity * 100) : 0;
                                  
