                                            <div className="px-3 py-2 border border-blue-300 rounded-lg bg-blue-100 font-mono text-right text-blue-900 font-semibold">
                                              ${(guaranteePerHead * headCount).toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                                            </div>
