                                            <div className="px-3 py-2 border border-orange-200 rounded-lg bg-orange-50 font-mono text-right text-orange-800 font-semibold">
                                              ${grossIndemnityTotal.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: 2})}
                                            </div>
