                                          const val = e.target.value;
                                          if (val === '' || /^[0-9]*\.?[0-9]*$/.test(val)) {
                                            const newProduction = { ...production };
                                            if (!newProduction[row.key]) newProduction[row.key] = {};
                                            newProduction[row.key] = { ...newProduction[row.key], [m]: val === '' ? 0 : (val.endsWith('.') ? val : parseFloat(val) || 0) };
                                            updateBS({ cashFlow: { ...(selectedBS?.cashFlow || {}), dairy: { ...dairy, production: newProduction } } });
                                          }
