                                            newCullCow[row.key] = { ...newCullCow[row.key], [m]: val === '' ? 0 : (val.endsWith('.') ? val : parseFloat(val) || 0) };
                                            updateBS({ cashFlow: { ...(selectedBS?.cashFlow || {}), dairy: { ...dairy, projCullCowSales: newCullCow } } });
