                                            const newBullCalf = { ...bullCalf };
                                            const filled = {};
                                            months.forEach(m => { filled[m] = num; });
                                            newBullCalf[row.key] = filled;
                                            updateBS({ cashFlow: { ...(selectedBS?.cashFlow || {}), dairy: { ...dairy, projBullCalfSales: newBullCalf } } });
