                                            const newBullCalf = { ...bullCalf };
                                            if (!newBullCalf[row.key]) newBullCalf[row.key] = {};
                                            newBullCalf[row.key] = { ...newBullCalf[row.key], [m]: val === '' ? 0 : (val.endsWith('.') ? val : parseFloat(val) || 0) };
