                              {['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'].map(m => (
                                <th key={m} className="py-2 px-2 text-center font-semibold w-24">{m}</th>
                              ))}
